+            "Provider {key} docs missing setup_guide"
+        );
+        assert!(
+            docs.get("capability_profile").is_some(),
+            "Provider {key} docs missing capability_profile"
+        );
+        assert!(
+            docs.get("status").is_some(),
+            "Provider {key} docs missing status"
+        );
